    ECOSYSTEM_DEBIAN = 'ECOSYSTEM_DEBIAN'
    ECOSYSTEM_GITHUB_ACTION = 'ECOSYSTEM_GITHUB_ACTION'
    ECOSYSTEM_COCOAPOD = 'ECOSYSTEM_COCOAPOD'
    ECOSYSTEM_APK = 'ECOSYSTEM_APK'
    ECOSYSTEM_CONTAINER = 'ECOSYSTEM_CONTAINER'
    ECOSYSTEM_HUGGING_FACE = 'ECOSYSTEM_HUGGING_FACE'
